def run_python_expression(expression: str) -> str:
    """Safely evaluate a Python expression (math, string ops, etc)."""
    import math
    allowed = {'__builtins__': {}, 'math': math, 'abs': abs, 'round': round,
               'min': min, 'max': max, 'sum': sum, 'len': len,
               'int': int, 'float': float, 'str': str, 'list': list,
               'sorted': sorted, 'range': range, 'enumerate': enumerate,
               'zip': zip, 'map': map, 'filter': filter, 'True': True,
               'False': False, 'None': None}
    try:
        result = eval(expression, allowed)
        return str(result)
    except Exception as e:
        return f'Error evaluating expression: {e}'

