def search_text(text: str, pattern: str) -> str:
    """Search text with a regex pattern, return JSON list of matches."""
    import re
    import json
    try:
        matches = re.findall(pattern, text)
        return json.dumps(matches[:100])
    except Exception as e:
        return f'Error in regex search: {e}'
